local _, STBS = ...
local frame=CreateFrame("Frame");frame:RegisterEvent("ADDON_LOADED");frame:RegisterEvent("PLAYER_REGEN_ENABLED")
frame:SetScript("OnEvent",function(_,event,arg)
  if event=="ADDON_LOADED" and arg==STBS.ADDON then STBS:InitializeDatabase();SLASH_STIERBLIZZSETTINGS1="/stier";SLASH_STIERBLIZZSETTINGS2="/stbs";SlashCmdList.STIERBLIZZSETTINGS=function(msg) msg=(msg or ""):lower();if msg=="graphics" then STBS:ShowText(STBS:L("GRAPHICS"),STBS:L("GRAPHICS_TEXT")) elseif msg=="interface" then STBS:ShowText(STBS:L("INTERFACE"),STBS:L("INTERFACE_TEXT")) elseif msg=="apply" then STBS:ShowText(STBS:L("TITLE"),STBS:L("HOME_TEXT")) elseif msg=="save" then local p=STBS:SaveCurrent(nil,{graphics=true,interfaceGameplay=true});STBS:ShowText(STBS:L("PROFILES"),STBS:L("PERSONAL")..": "..p.displayName) elseif msg=="export" then local p=STBS:SaveCurrent(nil,{graphics=true,interfaceGameplay=true});STBS:ShowExport(p) elseif msg=="import" then STBS:OpenImport() elseif msg=="backup" then STBS:CreateBackup({graphics=true,interfaceGameplay=true},"manual");STBS:Print("BACKUP_CREATED") elseif msg=="restore" then STBS:ShowText(STBS:L("BACKUPS"),STBS:L("RESTORE_ALL")) elseif msg=="debug" then STBS:ShowText(STBS:L("DIAGNOSTICS"),STBS:DiagnosticReport()) else STBS:ShowHome() end end
  end
